props.put("enable.auto.commit", "false");
while (running) {
  var records = consumer.poll(Duration.ofMillis(500));
  for (var r : records) {
    process(r);            // side effects must be idempotent
  }
  consumer.commitSync();   // commit ONLY after processing the batch
}

producer.initTransactions();
while (running) {
  var records = consumer.poll(Duration.ofMillis(500));
  producer.beginTransaction();
  for (var r : records)
    producer.send(new ProducerRecord<>("output", transform(r.value())));
  producer.sendOffsetsToTransaction(
      offsetsOf(records), consumer.groupMetadata());
  producer.commitTransaction();   // outputs + input offsets commit atomically
}
// consumers of 'output' set isolation.level=read_committed

